view_lkml:
view: cornerstone_metrics {
  sql_table_name: `axp-lumi.dw.cornerstone_metrics` ;;

  dimension: cornerstone_pk {
    primary_key: yes
    hidden: yes
    type: string
    sql: CONCAT(${TABLE}.bus_seg, '|', ${TABLE}.data_source, '|', CAST(${TABLE}.rpt_dt AS STRING)) ;;
    description: "Synthetic primary key combining business segment, data source, and report date for unique row identification."
  }

  dimension: business_segment {
    type: string
    sql: ${TABLE}.bus_seg ;;
    label: "Business Segment"
    description: "Card portfolio segment classification used to slice metrics across consumer, commercial, and global network business lines."
    group_label: "Segmentation"
    tags: ["segment", "business segment", "bus_seg"]
  }

  dimension: data_source {
    type: string
    sql: ${TABLE}.data_source ;;
    label: "Data Source"
    description: "Originating system that produced this metrics row. Cornerstone is the canonical default in nine of ten gold queries."
    tags: ["source", "system", "data_source"]
  }

  dimension: generation {
    type: string
    sql: ${TABLE}.generation ;;
    label: "Generation"
    description: "Cardmember generational cohort assignment used in lifecycle analytics and demographic segmentation."
  }

  dimension: sub_product_group {
    type: string
    sql: ${TABLE}.sub_product_group ;;
    label: "Sub Product Group"
    description: "Card sub-product grouping used to roll up product-level revenue and account metrics."
  }

  dimension: fico_band {
    type: string
    sql: ${TABLE}.fico_band ;;
    label: "FICO Band"
    description: "Credit risk band derived from FICO score, used to segment portfolio performance by creditworthiness tier."
  }

  dimension: accounts_in_force_raw {
    type: number
    sql: ${TABLE}.accounts_in_force ;;
    hidden: yes
    description: "Raw active account count column. Hidden \u2014 exposed via the total_accounts_in_force measure with the >0 filter baked in."
  }

  dimension_group: report {
    type: time
    timeframes: [raw, date, day_of_week, week, month, month_name, quarter, year]
    datatype: date
    convert_tz: no
    sql: ${TABLE}.rpt_dt ;;
    description: "Reporting date dimension exposing daily through yearly grains for time-series analysis of cornerstone metrics."
  }

  measure: total_billed_business {
    type: sum
    sql: ${TABLE}.billed_business ;;
    label: "Total Billed Business"
    description: "Sum of billed business volume in USD across the active filter set; the headline revenue measure for cornerstone metrics."
    value_format_name: usd
  }

  measure: total_new_accounts_acquired {
    type: sum
    sql: ${TABLE}.new_accounts_acquired ;;
    label: "Total New Accounts Acquired"
    description: "Sum of new accounts opened in the reporting period across the selected segment, source, and time slice."
    value_format_name: decimal_0
  }

  measure: avg_billed_business {
    type: average
    sql: ${TABLE}.billed_business ;;
    label: "Average Billed Business"
    description: "Average billed business per row in USD, useful for per-segment or per-cohort comparison rather than absolute totals."
    value_format_name: usd
  }

  measure: total_accounts_in_force {
    type: sum
    sql: ${TABLE}.accounts_in_force ;;
    label: "Accounts in Force"
    description: "Sum of accounts in force where the underlying count is positive, baking in the standard active-account filter."
    value_format_name: decimal_0
    filters: [accounts_in_force_raw: ">0"]
  }
}

explore_lkml:
explore: cornerstone_metrics {
  label: "Cornerstone Metrics"
  description: "Daily cornerstone metrics by segment, product, generation, FICO band, and reporting date. Answers questions about billed business totals, new account acquisition, and accounts in force across consumer and commercial portfolios."

  always_filter: {
    filters: [cornerstone_metrics.report_date: "last 12 months", cornerstone_metrics.data_source: "cornerstone"]
  }
}
